  1	import React, { useEffect, useState } from 'react';
  2	import { VirtualMachineModel } from 'src/views/dashboard-extensions/utils';
  3	
  4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  5	import { DescriptionModal } from '@kubevirt-utils/components/DescriptionModal/DescriptionModal';
  6	import { HARDWARE_DEVICE_TYPE } from '@kubevirt-utils/components/HardwareDevices/utils/constants';
  7	import HeadlessMode from '@kubevirt-utils/components/HeadlessMode/HeadlessMode';
  8	import HostnameModal from '@kubevirt-utils/components/HostnameModal/HostnameModal';
  9	import Loading from '@kubevirt-utils/components/Loading/Loading';
 10	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 11	import MoveVMToFolderModal from '@kubevirt-utils/components/MoveVMToFolderModal/MoveVMToFolderModal';
 12	import MutedTextSpan from '@kubevirt-utils/components/MutedTextSpan/MutedTextSpan';
 13	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
 14	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 15	import {
 16	  DISABLED_GUEST_SYSTEM_LOGS_ACCESS,
 17	  TREE_VIEW_FOLDERS,
 18	} from '@kubevirt-utils/hooks/useFeatures/constants';
 19	import { useFeatures } from '@kubevirt-utils/hooks/useFeatures/useFeatures';
 20	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 21	import { getPreferredBootmode } from '@kubevirt-utils/resources/preference/helper';
 22	import { asAccessReview, getAnnotation, getLabel, getName } from '@kubevirt-utils/resources/shared';
 23	import { DESCRIPTION_ANNOTATION, getDevices, getHostname } from '@kubevirt-utils/resources/vm';
 24	import { updateCustomizeInstanceType, vmSignal } from '@kubevirt-utils/store/customizeInstanceType';
 25	import { K8sVerb, useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 26	import { DescriptionList, Grid, GridItem, Switch, Title } from '@patternfly/react-core';
 27	import DetailsSectionBoot from '@virtualmachines/details/tabs/configuration/details/components/DetailsSectionBoot';
 28	import DetailsSectionHardware from '@virtualmachines/details/tabs/configuration/details/components/DetailsSectionHardware';
 29	import { VM_FOLDER_LABEL } from '@virtualmachines/tree/utils/constants';
 30	
 31	import usePreference from '../../hooks/usePreference';
 32	
 33	const CustomizeInstanceTypeDetailsTab = () => {
 34	  const vm = vmSignal.value;
 35	
 36	  const [preference, preferenceLoading] = usePreference(vm);
 37	
 38	  const { createModal } = useModal();
 39	  const { t } = useKubevirtTranslation();
 40	  const accessReview = asAccessReview(VirtualMachineModel, vm, 'update' as K8sVerb);
 41	  const [canUpdateVM] = useAccessReview(accessReview || {});
 42	
 43	  const { featureEnabled: isGuestSystemLogsDisabled } = useFeatures(
 44	    DISABLED_GUEST_SYSTEM_LOGS_ACCESS,
 45	  );
 46	  const { featureEnabled: treeViewFoldersEnabled } = useFeatures(TREE_VIEW_FOLDERS);
 47	
 48	  const logSerialConsole = vm?.spec?.template?.spec?.domain?.devices?.logSerialConsole;
 49	  const [isCheckedGuestSystemAccessLog, setIsCheckedGuestSystemAccessLog] = useState<boolean>();
 50	
 51	  useEffect(
 52	    () =>
 53	      setIsCheckedGuestSystemAccessLog(
 54	        logSerialConsole || (logSerialConsole === undefined && !isGuestSystemLogsDisabled),
 55	      ),
 56	    [isGuestSystemLogsDisabled, logSerialConsole],
 57	  );
 58	
 59	  const vmName = getName(vm);
 60	
 61	  if (!vm || preferenceLoading) {
 62	    return <Loading />;
 63	  }
 64	
 65	  return (
 66	    <div className="VirtualMachinesDetailsSection">
 67	      <Title headingLevel="h2">
 68	        <SearchItem id="details">{t('VirtualMachine details')}</SearchItem>
 69	      </Title>
 70	      <Grid>
 71	        <GridItem span={5}>
 72	          <DescriptionList className="pf-v6-c-description-list">
 73	            <VirtualMachineDescriptionItem
 74	              descriptionData={
 75	                getAnnotation(vm, DESCRIPTION_ANNOTATION) || <MutedTextSpan text={t('None')} />
 76	              }
 77	              onEditClick={() =>
 78	                createModal(({ isOpen, onClose }) => (
 79	                  <DescriptionModal
 80	                    onSubmit={(description) =>
 81	                      Promise.resolve(
 82	                        updateCustomizeInstanceType([
 83	                          {
 84	                            data: description,
 85	                            path: `metadata.annotations.${DESCRIPTION_ANNOTATION}`,
 86	                          },
 87	                        ]),
 88	                      )
 89	                    }
 90	                    isOpen={isOpen}
 91	                    obj={vm}
 92	                    onClose={onClose}
 93	                  />
 94	                ))
 95	              }
 96	              data-test-id={`${vmName}-description`}
 97	              descriptionHeader={<SearchItem id="description">{t('Description')}</SearchItem>}
 98	              isEdit
 99	            />
100	            {treeViewFoldersEnabled && (
101	              <VirtualMachineDescriptionItem
102	                onEditClick={() =>
103	                  createModal(({ isOpen, onClose }) => (
104	                    <MoveVMToFolderModal
105	                      onSubmit={(folderName) =>
106	                        Promise.resolve(
107	                          updateCustomizeInstanceType([
108	                            {
109	                              data: folderName,
110	                              path: ['metadata', 'labels', VM_FOLDER_LABEL],
111	                            },
112	                          ]),
113	                        )
114	                      }
115	                      isOpen={isOpen}
116	                      onClose={onClose}
117	                      vm={vm}
118	                    />
119	                  ))
120	                }
121	                data-test-id={`${vmName}-folder`}
122	                descriptionData={getLabel(vm, VM_FOLDER_LABEL)}
123	                descriptionHeader={<SearchItem id="folder">{t('Folder')}</SearchItem>}
124	                isEdit
125	              />
126	            )}
127	            <VirtualMachineDescriptionItem
128	              onEditClick={() =>
129	                createModal(({ isOpen, onClose }) => (
130	                  <HostnameModal
131	                    onSubmit={(updatedVM) =>
132	                      Promise.resolve(
133	                        updateCustomizeInstanceType([
134	                          {
135	                            data: getHostname(updatedVM),
136	                            path: `spec.template.spec.hostname`,
137	                          },
138	                        ]),
139	                      )
140	                    }
141	                    isOpen={isOpen}
142	                    onClose={onClose}
143	                    vm={vm}
144	                  />
145	                ))
146	              }
147	              data-test-id={`${vmName}-hostname`}
148	              descriptionData={vm?.spec?.template?.spec?.hostname || vmName}
149	              descriptionHeader={<SearchItem id="hostname">{t('Hostname')}</SearchItem>}
150	              isEdit
151	            />
152	            <VirtualMachineDescriptionItem
153	              bodyContent={t(
154	                'Whether to attach the default graphics device or not. VNC will not be available if checked.',
155	              )}
156	              descriptionData={
157	                <HeadlessMode
158	                  updateHeadlessMode={(checked) => {
159	                    return Promise.resolve(
160	                      updateCustomizeInstanceType([
161	                        {
162	                          data: checked ? false : null,
163	                          path: `spec.template.spec.domain.devices.autoattachGraphicsDevice`,
164	                        },
165	                      ]),
166	                    );
167	                  }}
168	                  vm={vm}
169	                />
170	              }
171	              breadcrumb="VirtualMachine.spec.template.devices.autoattachGraphicsDevice"
172	              data-test-id={`${vmName}-headless`}
173	              descriptionHeader={<SearchItem id="headless-mode">{t('Headless mode')}</SearchItem>}
174	              isPopover
175	            />
176	            <VirtualMachineDescriptionItem
177	              bodyContent={t(
178	                'Applying the start/pause mode to this Virtual Machine will cause it to partially reboot and pause.',
179	              )}
180	              descriptionData={
181	                <Switch
182	                  onChange={(_event, checked) => {
183	                    setIsCheckedGuestSystemAccessLog(checked);
184	                    updateCustomizeInstanceType([
185	                      {
186	                        data: checked,
187	                        path: `spec.template.spec.domain.devices.logSerialConsole`,
188	                      },
189	                    ]);
190	                  }}
191	                  id="guest-system-log-access"
192	                  isChecked={isCheckedGuestSystemAccessLog}
193	                  isDisabled={isGuestSystemLogsDisabled}
194	                />
195	              }
196	              descriptionHeader={
197	                <SearchItem id="guest-system-log-access">{t('Guest system log access')}</SearchItem>
198	              }
199	              data-test-id="guest-system-log-access"
200	              isPopover
201	            />
202	          </DescriptionList>
203	        </GridItem>
204	        <GridItem span={5}>
205	          <DescriptionList className="pf-v6-c-description-list">
206	            <DetailsSectionHardware
207	              onSubmit={(type: HARDWARE_DEVICE_TYPE, updatedVM: V1VirtualMachine) =>
208	                Promise.resolve(
209	                  updateCustomizeInstanceType([
210	                    {
211	                      data: getDevices(updatedVM)?.[type],
212	                      path: `spec.template.spec.domain.devices.${type}`,
213	                    },
214	                  ]),
215	                )
216	              }
217	              vm={vm}
218	            />
219	            <DetailsSectionBoot
220	              canUpdateVM={canUpdateVM}
221	              isCustomizeInstanceType
222	              preferredBootmode={getPreferredBootmode(preference)}
223	              vm={vm}
224	            />
225	          </DescriptionList>
226	        </GridItem>
227	      </Grid>
228	    </div>
229	  );
230	};
231	
232	export default CustomizeInstanceTypeDetailsTab;

